var surah048 = {
  number: 48,
  nameArabic: "al-Fath",
  nameEnglish: "Al-Fath",
  meaning: "The Victory",
  totalAyahs: 29,
  ayahs: [
    { number: 1, arabic: "إِنَّا فَتَحْنَا لَكَ فَتْحًۭا مُّبِينًۭا", transliteration: "Inna fatahna laka fathan mubeenan", transliterationB: "Innaa fatahnaa laka Fatham Mubeenaa", english: "Verily We have granted thee a manifest Victory", romanUrdu: "Aey Nabi, humne tumko khuli fatah ata kardi" },
    { number: 2, arabic: "لِّيَغْفِرَ لَكَ ٱللَّهُ مَا تَقَدَّمَ مِن ذَنۢبِكَ وَمَا تَأَخَّرَ وَيُتِمَّ نِعْمَتَهُۥ عَلَيْكَ وَيَهْدِيَكَ صِرَٰطًۭا مُّسْتَقِيمًۭا", transliteration: "Liyaghfira laka Allahu ma taqaddama min thanbika wama taakhkhara wayutimma niAAmatahu AAalayka wayahdiyaka siratan mustaqeeman", transliterationB: "Liyaghfira lakal laahu maa taqaddama min zambika wa maa ta akhkhara wa yutimma ni'matahoo 'alaika wa yahdiyaka siraatam mustaqeema", english: "That Allah may forgive thee thy faults of the past and those to follow; fulfil His favour to thee; and guide thee on the Straight Way", romanUrdu: "Taa-ke Allah tumhari agli pichli har kotahi se dargurzar farmaye, aur tumpar apni niyamat ki takmeel(poori) karde, aur tumhein seedha rasta dikhaye" },
    { number: 3, arabic: "وَيَنصُرَكَ ٱللَّهُ نَصْرًا عَزِيزًا", transliteration: "Wayansuraka Allahu nasran AAazeezan", transliterationB: "Wa yansurakal laahu nasran 'azeezaa", english: "And that Allah may help thee with powerful help", romanUrdu: "Aur tumko zabardast nusrat bakhshe" },
    { number: 4, arabic: "هُوَ ٱلَّذِىٓ أَنزَلَ ٱلسَّكِينَةَ فِى قُلُوبِ ٱلْمُؤْمِنِينَ لِيَزْدَادُوٓا۟ إِيمَٰنًۭا مَّعَ إِيمَٰنِهِمْ ۗ وَلِلَّهِ جُنُودُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًۭا", transliteration: "Huwa allathee anzala alssakeenata fee quloobi almumineena liyazdadoo eemanan maAAa eemanihim walillahi junoodu alssamawati waalardi wakana Allahu AAaleeman hakeeman", transliterationB: "Huwal lazeee anzalas sakeenata fee quloobil mu'mineena liyazdaadooo eemaanamma'a eemaanihim; wa lillaahi junoodus samawaati wal ard; wa kaanal laahu 'Aleeman Hakeemaa", english: "It is He Who sent down tranquillity into the hearts of the Believers, that they may add faith to their faith;- for to Allah belong the Forces of the heavens and the earth; and Allah is Full of Knowledge and Wisdom", romanUrdu: "Wahi hai jisne momino ke dilon mein sakinat ((Tranquility) nazil farmayi taa-ke apne imaan ke saath woh ek iman aur bada lein. Zameen aur aasmano ke sab lashkar Allah ke kabza-e-qudrat mein hain, aur woh Aleem o Hakeem hai" },
    { number: 5, arabic: "لِّيُدْخِلَ ٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَٰتِ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا وَيُكَفِّرَ عَنْهُمْ سَيِّـَٔاتِهِمْ ۚ وَكَانَ ذَٰلِكَ عِندَ ٱللَّهِ فَوْزًا عَظِيمًۭا", transliteration: "Liyudkhila almumineena waalmuminati jannatin tajree min tahtiha alanharu khalideena feeha wayukaffira AAanhum sayyiatihim wakana thalika AAinda Allahi fawzan AAatheeman", transliterationB: "Liyudkhilal mu'mineena walmu'minaati jannaatin tajree min tahtihal anhaaru khaalideena feehaa wa yukaffira 'anhum saiyi aatihim; wa kaana zaalika 'indal laahi fawzan 'azeemaa", english: "That He may admit the men and women who believe, to Gardens beneath which rivers flow, to dwell therein for aye, and remove their ills from them;- and that is, in the sight of Allah, the highest achievement (for man)", romanUrdu: "(Usne yeh kaam is liye kiya hai) taa-ke momin mardon aur auraton ko hamesha rehne ke liye aisi jannaton mein daakhil farmaye jinke nichey nehrein beh rahi hongi aur unki buraiyan unse dur karde. Allah ke nazdeek yeh badi kamiyabi hai" },
    { number: 6, arabic: "وَيُعَذِّبَ ٱلْمُنَٰفِقِينَ وَٱلْمُنَٰفِقَٰتِ وَٱلْمُشْرِكِينَ وَٱلْمُشْرِكَٰتِ ٱلظَّآنِّينَ بِٱللَّهِ ظَنَّ ٱلسَّوْءِ ۚ عَلَيْهِمْ دَآئِرَةُ ٱلسَّوْءِ ۖ وَغَضِبَ ٱللَّهُ عَلَيْهِمْ وَلَعَنَهُمْ وَأَعَدَّ لَهُمْ جَهَنَّمَ ۖ وَسَآءَتْ مَصِيرًۭا", transliteration: "WayuAAaththiba almunafiqeena waalmunafiqati waalmushrikeena waalmushrikati alththanneena biAllahi thanna alssawi AAalayhim dairatu alssawi waghadiba Allahu AAalayhim walaAAanahum waaAAadda lahum jahannama wasaat maseeran", transliterationB: "Wa yu'azzibal munaafiqeena walmunaafiqaati wal mushrikeena walmushrikaatiz zaaanneena billaahi zannas saw'; 'alaihim daaa'iratus saw'i wa ghadibal laahu 'alaihim wa la'anahum wa a'adda lahum jahannama wa saaa' at maseeraa", english: "And that He may punish the Hypocrites, men and women, and the Polytheists men and women, who imagine an evil opinion of Allah. On them is a round of Evil: the Wrath of Allah is on them: He has cursed them and got Hell ready for them: and evil is it for a destination", romanUrdu: "Aur un munafiq mardon aur auraton aur mushrik mardon aur auraton ko saza de jo Allah ke mutaliq burey gumaan rakhte hain. Burayi ke phair mein woh khud hi aa gaye hain, Allah ka gazab unpar hua aur usne unpar laanat ki aur unke liye jahannum muhayya kardi jo bahut hi bura thikana hai" },
    { number: 7, arabic: "وَلِلَّهِ جُنُودُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَكَانَ ٱللَّهُ عَزِيزًا حَكِيمًا", transliteration: "Walillahi junoodu alssamawati waalardi wakana Allahu AAazeezan hakeeman", transliterationB: "Wa lillaahi junoodus samaawaati wal ard; wa kaanal laahu 'azeezan hakeema", english: "For to Allah belong the Forces of the heavens and the earth; and Allah is Exalted in Power, Full of Wisdom", romanUrdu: "Zameen aur aasamano ke lashkar Allah hi ke qabza-e-qudrat mein hain aur woh zabardast aur hakeem(wise) hai" },
    { number: 8, arabic: "إِنَّآ أَرْسَلْنَٰكَ شَٰهِدًۭا وَمُبَشِّرًۭا وَنَذِيرًۭا", transliteration: "Inna arsalnaka shahidan wamubashshiran wanatheeran", transliterationB: "Innaaa arsalnaaka shaahi danw wa mubashshiranw wa nazeera", english: "We have truly sent thee as a witness, as a bringer of Glad Tidings, and as a Warner", romanUrdu: "Aey Nabi hunme tumko shahadat(witness) dene wala basharat(good news) dene wala aur khabardar kardene wala bana kar bheja hai" },
    { number: 9, arabic: "لِّتُؤْمِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَتُعَزِّرُوهُ وَتُوَقِّرُوهُ وَتُسَبِّحُوهُ بُكْرَةًۭ وَأَصِيلًا", transliteration: "Lituminoo biAllahi warasoolihi watuAAazziroohu watuwaqqiroohu watusabbihoohu bukratan waaseelan", transliterationB: "Litu minoo billaahi wa Rasoolihee wa tu'azziroohu watuwaqqiroohu watusabbi hoohu bukratanw wa aseelaa", english: "In order that ye (O men) may believe in Allah and His Messenger, that ye may assist and honour Him, and celebrate His praise morning and evening", romanUrdu: "Taa-ke aey logon , tum Allah aur uske Rasool par imaan lao aur uska saath do, uski taazim-o-tauqeer(support him, and revere ) karo aur subah o shaam uski tasbeeh karte raho" },
    { number: 10, arabic: "إِنَّ ٱلَّذِينَ يُبَايِعُونَكَ إِنَّمَا يُبَايِعُونَ ٱللَّهَ يَدُ ٱللَّهِ فَوْقَ أَيْدِيهِمْ ۚ فَمَن نَّكَثَ فَإِنَّمَا يَنكُثُ عَلَىٰ نَفْسِهِۦ ۖ وَمَنْ أَوْفَىٰ بِمَا عَٰهَدَ عَلَيْهُ ٱللَّهَ فَسَيُؤْتِيهِ أَجْرًا عَظِيمًۭا", transliteration: "Inna allatheena yubayiAAoonaka innama yubayiAAoona Allaha yadu Allahi fawqa aydeehim faman nakatha fainnama yankuthu AAala nafsihi waman awfa bima AAahada AAalayhu Allaha fasayuteehi ajran AAatheeman", transliterationB: "Innal lazeena yubaayi'oonaka innamaa yubaayi'oonal laaha yadul laahi fawqa aydehim; faman nakasa fainnamaa yuankusu 'alaa nafsihee wa man awfaa bimaa 'aahada 'alihul laaha fasa yu'teehi ajran 'azeemaa", english: "Verily those who plight their fealty to thee do no less than plight their fealty to Allah: the Hand of Allah is over their hands: then any one who violates his oath, does so to the harm of his own soul, and any one who fulfils what he has covenanted with Allah,- Allah will soon grant him a great Reward", romanUrdu: "Aey Nabi, jo log tumse bayt kar rahe thay(pledge allegiance to you) woh dar asal Allah se bayt kar rahey thay. Unke haath par Allah ka haath tha. Ab jo is ahad ko todeyga uski ahad shikani ka wabal uski apni hi zaat par hoga, aur jo us ahad ko wafa karega jo usne Allah se kiya hai, Allah ankqareeb usko bada ajar ata farmayega" },
    { number: 11, arabic: "سَيَقُولُ لَكَ ٱلْمُخَلَّفُونَ مِنَ ٱلْأَعْرَابِ شَغَلَتْنَآ أَمْوَٰلُنَا وَأَهْلُونَا فَٱسْتَغْفِرْ لَنَا ۚ يَقُولُونَ بِأَلْسِنَتِهِم مَّا لَيْسَ فِى قُلُوبِهِمْ ۚ قُلْ فَمَن يَمْلِكُ لَكُم مِّنَ ٱللَّهِ شَيْـًٔا إِنْ أَرَادَ بِكُمْ ضَرًّا أَوْ أَرَادَ بِكُمْ نَفْعًۢا ۚ بَلْ كَانَ ٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرًۢا", transliteration: "Sayaqoolu laka almukhallafoona mina alaAArabi shaghalatna amwaluna waahloona faistaghfir lana yaqooloona bialsinatihim ma laysa fee quloobihim qul faman yamliku lakum mina Allahi shayan in arada bikum darran aw arada bikum nafAAan bal kana Allahu bima taAAmaloona khabeeran", transliterationB: "Sa yaqoolu lakal mukhal lafoona minal-A'raabi shaighalatnaaa amwaalunaa wa ahloonaa fastaghfir lanaa; yaqooloona bi alsinatihim maa laisa fee quloobihim; qul famany yamliku lakum minal laahi shai'an in araada bikum darran aw araada bikum naf'aa; bal kaanal laahu bimaa ta'maloona Khabeeraa", english: "The desert Arabs who lagged behind will say to thee: \"We were engaged in (looking after) our flocks and herds, and our families: do thou then ask forgiveness for us.\" They say with their tongues what is not in their hearts. Say: \"Who then has any power at all (to intervene) on your behalf with Allah, if His Will is to give you some loss or to give you some profit? But Allah is well acquainted with all that ye do", romanUrdu: "Aey Nabi, badwi (bedouns) arabon mein se jo log pichey chodh diye gaye thay ab woh aa kar zaroor tumse kahenge ke humein apne amwal aur baal bacchon ki fikr ne mashgul kar rakkha tha. Aap hamare liye magfirat ki dua famayein. Yeh log apni zubaano se woh baatein kehte hain jo unke dilon mein nahin hoti. Unse kehna “acha, yahi baat hai to kaun tumhare maamle mein Allah ke faisle ko rok dene ka kuch bhi ikhtiyar rakhta hai agar woh tumhein koi nuksan pahunchana chahey ya nafa bakshna chahe? Tumhare aamal se to Allah hi ba-khabar hai" },
    { number: 12, arabic: "بَلْ ظَنَنتُمْ أَن لَّن يَنقَلِبَ ٱلرَّسُولُ وَٱلْمُؤْمِنُونَ إِلَىٰٓ أَهْلِيهِمْ أَبَدًۭا وَزُيِّنَ ذَٰلِكَ فِى قُلُوبِكُمْ وَظَنَنتُمْ ظَنَّ ٱلسَّوْءِ وَكُنتُمْ قَوْمًۢا بُورًۭا", transliteration: "Bal thanantum an lan yanqaliba alrrasoolu waalmuminoona ila ahleehim abadan wazuyyina thalika fee quloobikum wathanantum thanna alssawi wakuntum qawman booran", transliterationB: "Bal zanantum al lany yanqalibar Rasoolu walmu'minoona ilaaa ahleehim abadanw wa zuyyina zaalika fee quloobikum wa zanantum zannnas saw'i wa kuntum qawmam booraa", english: "Nay, ye thought that the Messenger and the Believers would never return to their families; this seemed pleasing in your hearts, and ye conceived an evil thought, for ye are a people lost (in wickedness)", romanUrdu: "(Magar asal baat woh nahin hai jo tum keh rahey ho) balke tumne yun samjha ke Rasool aur mominin apne ghar walon mein hargiz palat kar na aa sakenge aur yeh khayal tumhare dilon ko bahut bhala laga. Aur tumne bahut burey guman kiye aur tum sakht badh batin (immensely evil) log ho”" },
    { number: 13, arabic: "وَمَن لَّمْ يُؤْمِنۢ بِٱللَّهِ وَرَسُولِهِۦ فَإِنَّآ أَعْتَدْنَا لِلْكَٰفِرِينَ سَعِيرًۭا", transliteration: "Waman lam yumin biAllahi warasoolihi fainna aAAtadna lilkafireena saAAeeran", transliterationB: "Wa mal lam yu'mim billaahi wa Rasoolihee fainnaaa a'tadnaa lilkaafireena sa'eeraa", english: "And if any believe not in Allah and His Messenger, We have prepared, for those who reject Allah, a Blazing Fire", romanUrdu: "Allah aur uske Rasool par jo log imaan na rakhte hon aisey kaafiron ke liye humne bhadakti aag muhaiyya kar rakkhi hai" },
    { number: 14, arabic: "وَلِلَّهِ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ يَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۚ وَكَانَ ٱللَّهُ غَفُورًۭا رَّحِيمًۭا", transliteration: "Walillahi mulku alssamawati waalardi yaghfiru liman yashao wayuAAaththibu man yashao wakana Allahu ghafooran raheeman", transliterationB: "Wa lillaahii mulkus samaawaati wal ard; yaghfiru limany yashaaa'u wa yu'azzibu many yashaaa'; wa kaanal laahu Ghafoorar Raheemaa", english: "To Allah belongs the dominion of the heavens and the earth: He forgives whom He wills, and He punishes whom He wills: but Allah is Oft-Forgiving, Most Merciful", romanUrdu: "Aasmano aur zameen ki badshahi ka maalik Allah hi hai. Jisey chahe maaf karey aur jisey chahe saza de. Aur woh Gafoor o Raheem hai" },
    { number: 15, arabic: "سَيَقُولُ ٱلْمُخَلَّفُونَ إِذَا ٱنطَلَقْتُمْ إِلَىٰ مَغَانِمَ لِتَأْخُذُوهَا ذَرُونَا نَتَّبِعْكُمْ ۖ يُرِيدُونَ أَن يُبَدِّلُوا۟ كَلَٰمَ ٱللَّهِ ۚ قُل لَّن تَتَّبِعُونَا كَذَٰلِكُمْ قَالَ ٱللَّهُ مِن قَبْلُ ۖ فَسَيَقُولُونَ بَلْ تَحْسُدُونَنَا ۚ بَلْ كَانُوا۟ لَا يَفْقَهُونَ إِلَّا قَلِيلًۭا", transliteration: "Sayaqoolu almukhallafoona itha intalaqtum ila maghanima litakhuthooha tharoona nattabiAAkum yureedoona an yubaddiloo kalama Allahi qul lan tattabiAAoona kathalikum qala Allahu min qablu fasayaqooloona bal tahsudoonana bal kanoo la yafqahoona illa qaleelan", transliterationB: "Sa yaqoolul mukhalla foona izan talaqtum ilaa maghaanima litaakhuzoohaa zaroonaa nattabi'kum yureedoona any yubaddiloo Kalaamallaah; qul lan tattabi'oonaa kazaalikum qaalal laahu min qablu fasa yaqooloona bal tahsudoonanna; bal kaanoo laa yafqahoona illaa qaleela", english: "Those who lagged behind (will say), when ye (are free to) march and take booty (in war): \"Permit us to follow you.\" They wish to change Allah's decree: Say: \"Not thus will ye follow us: Allah has already declared (this) beforehand\": then they will say, \"But ye are jealous of us.\" Nay, but little do they understand (such things)", romanUrdu: "Jab tum maal-e-ganimat hasil karne ke liye jane lagoge to yeh pichey chodey jane waley log tumse zaroor kahenge ke humein bhi apne saath chalne do. Yeh chahte hain ke Allah ke farmaan ko badal dein. Inse saaf keh dena ke “Tum hargiz hamare saath nahin chal sakte. Allah pehle hi yeh farma chuka hai” yeh kahenge ke “nahin, balke tumlog humse hasad kar rahey ho” (halanke baat hasad ki nahin hai) balke yeh log sahih baat ko kam hi samajhte hain" },
    { number: 16, arabic: "قُل لِّلْمُخَلَّفِينَ مِنَ ٱلْأَعْرَابِ سَتُدْعَوْنَ إِلَىٰ قَوْمٍ أُو۟لِى بَأْسٍۢ شَدِيدٍۢ تُقَٰتِلُونَهُمْ أَوْ يُسْلِمُونَ ۖ فَإِن تُطِيعُوا۟ يُؤْتِكُمُ ٱللَّهُ أَجْرًا حَسَنًۭا ۖ وَإِن تَتَوَلَّوْا۟ كَمَا تَوَلَّيْتُم مِّن قَبْلُ يُعَذِّبْكُمْ عَذَابًا أَلِيمًۭا", transliteration: "Qul lilmukhallafeena mina alaAArabi satudAAawna ila qawmin olee basin shadeedin tuqatiloonahum aw yuslimoona fain tuteeAAoo yutikumu Allahu ajran hasanan wain tatawallaw kama tawallaytum min qablu yuAAaththibkum AAathaban aleeman", transliterationB: "Qul lilmukhallafeena minal A'raabi satud'awna ilaa qawmin ulee baasin shadeedin tuqaati loonahum aw yuslimoona fa in tutee'oo yu'tikumul laahu ajran hasananw wa in tatawallaw kamaa tawallaitum min qablu yu'azzibkum 'azaaban aleemaa", english: "Say to the desert Arabs who lagged behind: \"Ye shall be summoned (to fight) against a people given to vehement war: then shall ye fight, or they shall submit. Then if ye show obedience, Allah will grant you a goodly reward, but if ye turn back as ye did before, He will punish you with a grievous Penalty", romanUrdu: "In pichey chodey janey waley badwi(bedouin) arabon se kehna ke “ankareeb tumhein aisey logon se ladne ke liye bulaya jayega jo badey zoarawar hain. Tumko unse jung karni hogi ya woh mutii (surrender) ho jayenge. Us waqt agar tumne hukum e jihad ki itaat ki to Allah tumhein accha ajar dega. Aur agar tum phir usi tarah mooh moad gaye jis tarah pehle moad chuke ho to Allah tumko dardnaak saza dega" },
    { number: 17, arabic: "لَّيْسَ عَلَى ٱلْأَعْمَىٰ حَرَجٌۭ وَلَا عَلَى ٱلْأَعْرَجِ حَرَجٌۭ وَلَا عَلَى ٱلْمَرِيضِ حَرَجٌۭ ۗ وَمَن يُطِعِ ٱللَّهَ وَرَسُولَهُۥ يُدْخِلْهُ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ ۖ وَمَن يَتَوَلَّ يُعَذِّبْهُ عَذَابًا أَلِيمًۭا", transliteration: "Laysa AAala alaAAma harajun wala AAala alaAAraji harajun wala AAala almareedi harajun waman yutiAAi Allaha warasoolahu yudkhilhu jannatin tajree min tahtiha alanharu waman yatawalla yuAAaththibhu AAathaban aleeman", transliterationB: "Laisa 'alal a'maa harajunw wa laa 'alal a'raji harajunw wa laa 'alal mareedi haraj' wa many yutil'il laaha wa Rasoolahoo yudkhilhu jannaatin tajree min tahtihal anhaaru wa many yatawalla yu'azzibhu 'azaaban aleemaa", english: "No blame is there on the blind, nor is there blame on the lame, nor on one ill (if he joins not the war): But he that obeys Allah and his Messenger,- (Allah) will admit him to Gardens beneath which rivers flow; and he who turns back, (Allah) will punish him with a grievous Penalty", romanUrdu: "Agar andha aur langda aur mareez jihad ke liye na aaye to koi haraj nahin. Jo koi Allah aur uske Rasool ki itaat karega Allah usey un jannaton mein dakhil karega jinke nichey nehrein beh rahi hongi, aur jo mooh pherega usey woh dardnaak azaab dega”" },
    { number: 18, arabic: "۞ لَّقَدْ رَضِىَ ٱللَّهُ عَنِ ٱلْمُؤْمِنِينَ إِذْ يُبَايِعُونَكَ تَحْتَ ٱلشَّجَرَةِ فَعَلِمَ مَا فِى قُلُوبِهِمْ فَأَنزَلَ ٱلسَّكِينَةَ عَلَيْهِمْ وَأَثَٰبَهُمْ فَتْحًۭا قَرِيبًۭا", transliteration: "Laqad radiya Allahu AAani almumineena ith yubayiAAoonaka tahta alshshajarati faAAalima ma fee quloobihim faanzala alsakeenata AAalayhim waathabahum fathan qareeban", transliterationB: "Laqad radiyal laahu 'anil mu'mineena iz yubaayi 'oonaka tahtash shajarati fa'alima maa fee quloobihim fa anzalas sakeenata 'alaihim wa asaa bahum fat han qareebaa", english: "Allah's Good Pleasure was on the Believers when they swore Fealty to thee under the Tree: He knew what was in their hearts, and He sent down Tranquillity to them; and He rewarded them with a speedy Victory", romanUrdu: "Allah momino se khush ho gaya jab woh darakht ke nichey tumse bayt (swore allegiance) kar rahey thay. Unke dilon ka haal usko maloom tha. Is liye usne unpar sakinat(inner peace) nazil farmayi, unko inaam mein qareebi fatah bakshi" },
    { number: 19, arabic: "وَمَغَانِمَ كَثِيرَةًۭ يَأْخُذُونَهَا ۗ وَكَانَ ٱللَّهُ عَزِيزًا حَكِيمًۭا", transliteration: "Wamaghanima katheeratan yakhuthoonaha wakana Allahu AAazeezan hakeeman", transliterationB: "Wa maghaanima kaseera tany yaakhuzoonahaa; wa kaanal laahu 'Azeezan Hakeemaa", english: "And many gains will they acquire (besides): and Allah is Exalted in Power, Full of Wisdom", romanUrdu: "Aur bahut sa maal-e-ganimat unhein ata kar diya jisey woh (anqareeb) hasil karenge. Allah zabardast aur hakeem(wise) hai" },
    { number: 20, arabic: "وَعَدَكُمُ ٱللَّهُ مَغَانِمَ كَثِيرَةًۭ تَأْخُذُونَهَا فَعَجَّلَ لَكُمْ هَٰذِهِۦ وَكَفَّ أَيْدِىَ ٱلنَّاسِ عَنكُمْ وَلِتَكُونَ ءَايَةًۭ لِّلْمُؤْمِنِينَ وَيَهْدِيَكُمْ صِرَٰطًۭا مُّسْتَقِيمًۭا", transliteration: "WaAAadakumu Allahu maghanima katheeratan takhuthoonaha faAAajjala lakum hathihi wakaffa aydiya alnnasi AAankum walitakoona ayatan lilmumineena wayahdiyakum siratan mustaqeeman", transliterationB: "Wa'adakumul laahu ma ghaanima kaseeratan taakhuzoo nahaa fa'ajjala lakum haazihee wa kaffa aydiyan naasi 'ankum wa litakoona aayatal lilmu'mineena wa yahdiyakum siraatam mustaqeema", english: "Allah has promised you many gains that ye shall acquire, and He has given you these beforehand; and He has restrained the hands of men from you; that it may be a Sign for the Believers, and that He may guide you to a Straight Path", romanUrdu: "Allah tumse ba-kasrat amwal-e-ganimat ka wada karta hai jinhein tum hasil karoge. Fauri taur par to yeh fatah usne tumhein ata kardi aur logon ke haath tumhare khilaf uthne se roak diye, taa-ke yeh momino ke liye ek nishani ban jaye aur Allah seedhe raaste ki taraf tumhein hidayat bakshe" },
    { number: 21, arabic: "وَأُخْرَىٰ لَمْ تَقْدِرُوا۟ عَلَيْهَا قَدْ أَحَاطَ ٱللَّهُ بِهَا ۚ وَكَانَ ٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرًۭا", transliteration: "Waokhra lam taqdiroo AAalayha qad ahata Allahu biha wakana Allahu AAala kulli shayin qadeeran", transliterationB: "Wa ukhraa lam taqdiroo 'alaihaa qad ahaatal laahu bihaa; wa kaanal laahu 'alaa kulli shai'in qadeera", english: "And other gains (there are), which are not within your power, but which Allah has compassed: and Allah has power over all things", romanUrdu: "Iske alawa dusre aur ganimaton ka bhi woh tumse waada karta hai jinpar tum abhi tak qadir nahin huey ho aur Allah ne inko gher rakkha hai, Allah har cheez par qadir hai" },
    { number: 22, arabic: "وَلَوْ قَٰتَلَكُمُ ٱلَّذِينَ كَفَرُوا۟ لَوَلَّوُا۟ ٱلْأَدْبَٰرَ ثُمَّ لَا يَجِدُونَ وَلِيًّۭا وَلَا نَصِيرًۭا", transliteration: "Walaw qatalakumu allatheena kafaroo lawallawoo aladbara thumma la yajidoona waliyyan wala naseeran", transliterationB: "Wa law qaatalakumul lazeena kafaroo la wallawul adbaara summa laa yajidoona waliyanw-wa laa naseeraa", english: "If the Unbelievers should fight you, they would certainly turn their backs; then would they find neither protector nor helper", romanUrdu: "Yeh kafir log agar is waqt tumse ladd gaye hotey to yaqeenan peeth pher jaatey aur koi haami o madadgaar na paate" },
    { number: 23, arabic: "سُنَّةَ ٱللَّهِ ٱلَّتِى قَدْ خَلَتْ مِن قَبْلُ ۖ وَلَن تَجِدَ لِسُنَّةِ ٱللَّهِ تَبْدِيلًۭا", transliteration: "Sunnata Allahi allatee qad khalat min qablu walan tajida lisunnati Allahi tabdeelan", transliterationB: "Sunnatal laahil latee qad khalat min qablu wa lan tajida lisunnatil laahi tabdeelaa", english: "(Such has been) the practice (approved) of Allah already in the past: no change wilt thou find in the practice (approved) of Allah", romanUrdu: "Yeh Allah ki sunnat hai jo pehle se chali aa rahi hai aur tum Allah ki sunnat mein koi tabdili na paogey" },
    { number: 24, arabic: "وَهُوَ ٱلَّذِى كَفَّ أَيْدِيَهُمْ عَنكُمْ وَأَيْدِيَكُمْ عَنْهُم بِبَطْنِ مَكَّةَ مِنۢ بَعْدِ أَنْ أَظْفَرَكُمْ عَلَيْهِمْ ۚ وَكَانَ ٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرًا", transliteration: "Wahuwa allathee kaffa aydiyahum AAankum waaydiyakum AAanhum bibatni makkata min baAAdi an athfarakum AAalayhim wakana Allahu bima taAAmaloona baseeran", transliterationB: "Wa Huwal lazee kaffa aydiyahum 'ankum wa aydiyakum 'anhum bibatni Makkata mim ba'di an azfarakum 'alaihim; wa kaanal laahu bimaa ta'maloona Baseera", english: "And it is He Who has restrained their hands from you and your hands from them in the midst of Makka, after that He gave you the victory over them. And Allah sees well all that ye do", romanUrdu: "Wahi hai jisne Makkah ki wadi mein unke haath tumse aur tumhare haath unse roak diye, halanke woh unpar tumhein galaba ata kar chuka tha aur jo kuch tum kar rahey thay Allah usey dekh raha tha" },
    { number: 25, arabic: "هُمُ ٱلَّذِينَ كَفَرُوا۟ وَصَدُّوكُمْ عَنِ ٱلْمَسْجِدِ ٱلْحَرَامِ وَٱلْهَدْىَ مَعْكُوفًا أَن يَبْلُغَ مَحِلَّهُۥ ۚ وَلَوْلَا رِجَالٌۭ مُّؤْمِنُونَ وَنِسَآءٌۭ مُّؤْمِنَٰتٌۭ لَّمْ تَعْلَمُوهُمْ أَن تَطَـُٔوهُمْ فَتُصِيبَكُم مِّنْهُم مَّعَرَّةٌۢ بِغَيْرِ عِلْمٍۢ ۖ لِّيُدْخِلَ ٱللَّهُ فِى رَحْمَتِهِۦ مَن يَشَآءُ ۚ لَوْ تَزَيَّلُوا۟ لَعَذَّبْنَا ٱلَّذِينَ كَفَرُوا۟ مِنْهُمْ عَذَابًا أَلِيمًا", transliteration: "Humu allatheena kafaroo wasaddookum AAani almasjidi alharami waalhadya maAAkoofan an yablugha mahillahu walawla rijalun muminoona wanisaon muminatun lam taAAlamoohum an tataoohum fatuseebakum minhum maAAarratun bighayri AAilmin liyudkhila Allahu fee rahmatihi man yashao law tazayyaloo laAAaththabna allatheena kafaroo minhum AAathaban aleeman", transliterationB: "Humul lazeena kafaroo wa saddookum 'anil-Masjidil-Haraami walhadya ma'koofan any yablugha mahillah; wa law laa rijaalum mu'minoona wa nisaaa'um mu'minaatul lam ta'lamoohum an tata'oohum fatuseebakum minhum ma'arratum bighairi 'ilmin liyud khilal laahu fee rahmatihee many yashaaa'; law tazayyaloo la'azzabnal lazeena kafaroo minhum 'azaaban aleema", english: "They are the ones who denied Revelation and hindered you from the Sacred Mosque and the sacrificial animals, detained from reaching their place of sacrifice. Had there not been believing men and believing women whom ye did not know that ye were trampling down and on whose account a crime would have accrued to you without (your) knowledge, (Allah would have allowed you to force your way, but He held back your hands) that He may admit to His Mercy whom He will. If they had been apart, We should certainly have punished the Unbelievers among them with a grievous Punishment", romanUrdu: "Whai log to hain jinhon ne kufr kiya aur tumko masjid e haram se roka aur haadi(qurbani) ke Unton (camels) ko unki qurbani ki jagah na pahunchne diya. Agar (Makkah mein) aisey momin Mard o aurat maujood na hotay jinhein tum nahin jante, aur yeh khatra na hota ke nadanastagi mein tum unhein pamaal kardoge aur ussey tumpar haraf aayega (to jung na roaki jati. roaki woh is liye gayi) taa-ke Allah apni rehmat mein jisko chahe daakhil karle. Woh momin alag ho gaye hotey to (ehle Makkah mein se) jo kafir thay unko hum zaroor sakht saza dete" },
    { number: 26, arabic: "إِذْ جَعَلَ ٱلَّذِينَ كَفَرُوا۟ فِى قُلُوبِهِمُ ٱلْحَمِيَّةَ حَمِيَّةَ ٱلْجَٰهِلِيَّةِ فَأَنزَلَ ٱللَّهُ سَكِينَتَهُۥ عَلَىٰ رَسُولِهِۦ وَعَلَى ٱلْمُؤْمِنِينَ وَأَلْزَمَهُمْ كَلِمَةَ ٱلتَّقْوَىٰ وَكَانُوٓا۟ أَحَقَّ بِهَا وَأَهْلَهَا ۚ وَكَانَ ٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمًۭا", transliteration: "Ith jaAAala allatheena kafaroo fee quloobihimu alhamiyyata hamiyyata aljahiliyyati faanzala Allahu sakeenatahu AAala rasoolihi waAAala almumineena waalzamahum kalimata alttaqwa wakanoo ahaqqa biha waahlaha wakana Allahu bikulli shayin AAaleeman", transliterationB: "Iz ja'alal lazeena kafaroo fee quloobihimul hamiyyata hamiyyatal jaahiliyyati fa anzalal laahu sakeenatahoo 'alaa Rasoolihee wa 'alal mu mineena wa alzamahum kalimatat taqwaa wa kaanooo ahaqqa bihaa wa ahlahaa; wa kaanal laahu bikulli shai'in Aleema", english: "While the Unbelievers got up in their hearts heat and cant - the heat and cant of ignorance,- Allah sent down His Tranquillity to his Messenger and to the Believers, and made them stick close to the command of self-restraint; and well were they entitled to it and worthy of it. And Allah has full knowledge of all things", romanUrdu: "(Yahi wajah hai ke) jab in kafiron ne apne dilon mei jaahilana hamiyat bitha li to Allah ne apne Rasool aur momino par sakinat nazil farmayi aur momino ko taqwa ki baat ka paband rakkha, ke wahi uske zyada haqdar aur uske ahel thay. Allah har cheez ka ilm rakhta hai" },
    { number: 27, arabic: "لَّقَدْ صَدَقَ ٱللَّهُ رَسُولَهُ ٱلرُّءْيَا بِٱلْحَقِّ ۖ لَتَدْخُلُنَّ ٱلْمَسْجِدَ ٱلْحَرَامَ إِن شَآءَ ٱللَّهُ ءَامِنِينَ مُحَلِّقِينَ رُءُوسَكُمْ وَمُقَصِّرِينَ لَا تَخَافُونَ ۖ فَعَلِمَ مَا لَمْ تَعْلَمُوا۟ فَجَعَلَ مِن دُونِ ذَٰلِكَ فَتْحًۭا قَرِيبًا", transliteration: "Laqad sadaqa Allahu rasoolahu alrruya bialhaqqi latadkhulunna almasjida alharama in shaa Allahu amineena muhalliqeena ruoosakum wamuqassireena la takhafoona faAAalima ma lam taAAlamoo fajaAAala min dooni thalika fathan qareeban", transliterationB: "Laqad sadaqal laahu Rasoolahur ru'yaa bilhaqq, latadkhulunnal Masjidal-Haraama in shaaa'al laahu aamineena muhalliqeena ru'oosakum wa muqassireena laa takhaafoona fa'alima maa lam ta'lamoo faja'ala min dooni zaalika fathan qareebaa", english: "Truly did Allah fulfil the vision for His Messenger: ye shall enter the Sacred Mosque, if Allah wills, with minds secure, heads shaved, hair cut short, and without fear. For He knew what ye knew not, and He granted, besides this, a speedy victory", romanUrdu: "Fil waqeh Allah ne apne Rasool ko saccha khwab dikhaya tha jo theek theek haqq ke mutabiq tha. Insha Allah tum zaroor masjid e haram mein purey aman ke saath dakhil hongey, apne sar mundwa-ogey (shave) aur baal tarashwa-ogey aur tumhein koi khauff na hoga. Woh us baat ko janta tha jisey tum na jante thay is liye woh khwab pura honay se pehle usne yeh qareebi fatah tumko ata farmadi" },
    { number: 28, arabic: "هُوَ ٱلَّذِىٓ أَرْسَلَ رَسُولَهُۥ بِٱلْهُدَىٰ وَدِينِ ٱلْحَقِّ لِيُظْهِرَهُۥ عَلَى ٱلدِّينِ كُلِّهِۦ ۚ وَكَفَىٰ بِٱللَّهِ شَهِيدًۭا", transliteration: "Huwa allathee arsala rasoolahu bialhuda wadeeni alhaqqi liyuthhirahu AAala alddeeni kullihi wakafa biAllahi shaheedan", transliterationB: "Huwal lazeee arsala Rasoolahoo bilhudaa wa deenil haqqi liyuzhirahoo 'alad deeni kullih; wa kafaa billaahi Shaheeda", english: "It is He Who has sent His Messenger with Guidance and the Religion of Truth, to proclaim it over all religion: and enough is Allah for a Witness", romanUrdu: "Woh Allah hi hai jisne apne Rasool ko hidayat aur deen e haqq ke saath bheja hai taa-ke usko purey jins-e-din par gaalib karde (prevail over every religion) aur is haqeeqat par Allah ki gawahi kaafi hai" },
    { number: 29, arabic: "مُّحَمَّدٌۭ رَّسُولُ ٱللَّهِ ۚ وَٱلَّذِينَ مَعَهُۥٓ أَشِدَّآءُ عَلَى ٱلْكُفَّارِ رُحَمَآءُ بَيْنَهُمْ ۖ تَرَىٰهُمْ رُكَّعًۭا سُجَّدًۭا يَبْتَغُونَ فَضْلًۭا مِّنَ ٱللَّهِ وَرِضْوَٰنًۭا ۖ سِيمَاهُمْ فِى وُجُوهِهِم مِّنْ أَثَرِ ٱلسُّجُودِ ۚ ذَٰلِكَ مَثَلُهُمْ فِى ٱلتَّوْرَىٰةِ ۚ وَمَثَلُهُمْ فِى ٱلْإِنجِيلِ كَزَرْعٍ أَخْرَجَ شَطْـَٔهُۥ فَـَٔازَرَهُۥ فَٱسْتَغْلَظَ فَٱسْتَوَىٰ عَلَىٰ سُوقِهِۦ يُعْجِبُ ٱلزُّرَّاعَ لِيَغِيظَ بِهِمُ ٱلْكُفَّارَ ۗ وَعَدَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ مِنْهُم مَّغْفِرَةًۭ وَأَجْرًا عَظِيمًۢا", transliteration: "Muhammadun rasoolu Allahi waallatheena maAAahu ashiddao AAala alkuffari ruhamao baynahum tarahum rukkaAAan sujjadan yabtaghoona fadlan mina Allahi waridwanan seemahum fee wujoohihim min athari alssujoodi thalika mathaluhum fee alttawrati wamathaluhum fee alinjeeli kazarAAin akhraja shatahu faazarahu faistaghlatha faistawa AAala sooqihi yuAAjibu alzzurraAAa liyagheetha bihimu alkuffara waAAada Allahu allatheena amanoo waAAamiloo alssalihati minhum maghfiratan waajran AAatheeman", transliterationB: "Muhammadur Rasoolul laah; wallazeena ma'ahooo ashiddaaa'u 'alal kuffaaari ruhamaaa'u bainahum taraahum rukka'an sujjadany yabtaghoona fadlam minal laahi wa ridwaanan seemaahum fee wujoohihim min asaris sujood; zaalika masaluhum fit tawraah; wa masaluhum fil Injeeli kazar'in akhraja shat 'ahoo fa 'aazarahoo fastaghlaza fastawaa 'alaa sooqihee yu'jibuz zurraa'a liyagheeza bihimul kuffaar; wa'adal laahul lazeena aamanoo wa 'amilus saalihaati minhum maghfiratanw wa ajran 'azeemaa", english: "Muhammad is the messenger of Allah; and those who are with him are strong against Unbelievers, (but) compassionate amongst each other. Thou wilt see them bow and prostrate themselves (in prayer), seeking Grace from Allah and (His) Good Pleasure. On their faces are their marks, (being) the traces of their prostration. This is their similitude in the Taurat; and their similitude in the Gospel is: like a seed which sends forth its blade, then makes it strong; it then becomes thick, and it stands on its own stem, (filling) the sowers with wonder and delight. As a result, it fills the Unbelievers with rage at them. Allah has promised those among them who believe and do righteous deeds forgiveness, and a great Reward", romanUrdu: "Muhammad Allah ke Rasool hain, aur jo log unke saath hain woh kuffar par sakht aur aapas mein raheem hain. Tum jab dekhoge unhein ruku va sujood aur Allah ke fazl aur uski khushnudi ki talab mein mashgul paogey. Sujood ke asarat unke chehron par maujood hain jinse woh alag pehchane jatey hain. Yeh hai unki sifat Taurat mein. Aur Injeel mein unki misal yun di gayi hai ke goya ek kheti hai jisne pehle kopal nikali, phir us ko taqviyat di, phir woh gadhrayi, phir apne tanay (stem) par khadi ho gayi. Kaasht (sowers) karne walon ko woh khush karti hai taa-ke kuffar inke phalne phoolne par jalein (enraged). Is giroh ke log jo imaan laye hain aur jinhon ne neik amal kiye hain Allah ne unse magfirat aur bade ajar ka waada farmaya hai" }
  ]
};
